-- ==========================================
-- SOURCE: 044_fix_play_spin_segments.sql
-- ==========================================

-- Migration 044: Fix play_spin to use Dynamic Segments
-- Addresses "erroneous results" by respecting the actual segment count of the active wheel

CREATE OR REPLACE FUNCTION play_spin(
  p_queue_id UUID,
  p_screen_number INTEGER
) RETURNS JSONB AS $$
DECLARE
  v_player RECORD;
  v_result INTEGER;
  v_spins_remaining INTEGER;
  v_wheel_id UUID;
  v_segment_count INTEGER;
  v_rnd_index INTEGER;
BEGIN
  -- 1. VERIFY IDENTITY & STATE
  SELECT pq.*, pt.total_spins, pt.spins_consumed, pt.package_code
  INTO v_player
  FROM player_queue pq
  LEFT JOIN package_tracking pt ON pq.package_tracking_id = pt.id
  WHERE pq.id = p_queue_id 
    AND pq.screen_number = p_screen_number
    AND pq.status IN ('selecting', 'playing', 'ready');

  IF v_player IS NULL THEN
     RETURN jsonb_build_object('success', false, 'message', 'Jugador no autorizado o estado inválido');
  END IF;

  -- 2. VERIFY PACKAGE BALANCE
  IF v_player.package_tracking_id IS NOT NULL THEN
     IF (v_player.spins_consumed >= v_player.total_spins) THEN
        RETURN jsonb_build_object('success', false, 'message', 'No quedan giros disponibles');
     END IF;
  END IF;

  -- 3. DETERMINE RESULT (Dynamic Server Authority)
  
  -- A. Detect Active Wheel
  SELECT current_wheel_id INTO v_wheel_id
  FROM screen_state
  WHERE screen_number = p_screen_number;

  -- B. Calculate Result based on Wheel Type
  IF v_wheel_id IS NOT NULL THEN
     -- Custom Wheel: Count segments
     SELECT count(*) INTO v_segment_count
     FROM individual_wheel_segments
     WHERE wheel_id = v_wheel_id;

     IF v_segment_count > 0 THEN
        -- Pick a random segment index (0 to N-1)
        v_rnd_index := floor(random() * v_segment_count)::INTEGER;
        
        -- Get the ACTUAL position ID at that index
        -- (This handles non-contiguous positions safely)
        SELECT position INTO v_result
        FROM individual_wheel_segments
        WHERE wheel_id = v_wheel_id
        ORDER BY position ASC
        LIMIT 1 OFFSET v_rnd_index;
     ELSE
        -- Fallback if wheel has no segments (should not happen)
        v_result := floor(random() * 12) + 1;
     END IF;
  ELSE
     -- Default / Group Mode: Standard 36 Animals
     v_result := floor(random() * 36) + 1;
  END IF;

  -- 4. ATOMIC UPDATE
  
  -- A. Update Player Queue
  UPDATE player_queue
  SET 
    spin_result = v_result,
    status = 'playing'
  WHERE id = p_queue_id;

  -- B. Update Screen State
  UPDATE screen_state
  SET 
    status = 'spinning',
    last_spin_result = v_result,
    updated_at = now()
  WHERE screen_number = p_screen_number;

  -- C. Deduct Credit
  IF v_player.package_tracking_id IS NOT NULL THEN
    UPDATE package_tracking 
    SET spins_consumed = spins_consumed + 1, last_used_at = now()
    WHERE id = v_player.package_tracking_id;
    
    IF v_player.package_code IS NOT NULL THEN
        UPDATE game_packages
        SET plays_used = COALESCE(plays_used, 0) + 1
        WHERE code = v_player.package_code;
    END IF;
    
    v_spins_remaining := v_player.total_spins - (v_player.spins_consumed + 1);
  ELSE
    v_spins_remaining := 0;
  END IF;

  -- 5. RETURN RESULT
  RETURN jsonb_build_object(
    'success', true,
    'result_index', v_result,
    'spins_remaining', v_spins_remaining
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'message', SQLERRM);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION play_spin IS 'Updated Server Authority: Dynamically generates result based on active wheel segments (or 36 for default).';


-- ==========================================
-- SOURCE: 045_consolidate_identity.sql
-- ==========================================

-- Migration 045: Consolidate Identity and Cleanup (Fixed)
-- 1. Drop constraints on ALL tables referencing players
-- 2. Drop old table
-- 3. Update profiles
-- 4. Re-create FKs pointing to profiles

-- 1. DROP FKs from dependent tables
ALTER TABLE public.player_queue DROP CONSTRAINT IF EXISTS player_queue_player_id_fkey;
ALTER TABLE public.screen_state DROP CONSTRAINT IF EXISTS screen_state_player_id_fkey;
ALTER TABLE public.raffle_tickets DROP CONSTRAINT IF EXISTS raffle_tickets_player_id_fkey;

-- 2. DROP players table
DROP TABLE IF EXISTS public.players;

-- 3. ENRICH profiles table with stats
ALTER TABLE public.profiles 
ADD COLUMN IF NOT EXISTS total_plays INTEGER DEFAULT 0,
ADD COLUMN IF NOT EXISTS total_wins INTEGER DEFAULT 0,
ADD COLUMN IF NOT EXISTS last_played_at TIMESTAMPTZ;

-- 4. UPDATE FKs to reference profiles
-- player_queue
ALTER TABLE public.player_queue 
ADD CONSTRAINT player_queue_player_id_fkey 
FOREIGN KEY (player_id) REFERENCES public.profiles(id) ON DELETE SET NULL;

-- screen_state
ALTER TABLE public.screen_state 
ADD CONSTRAINT screen_state_player_id_fkey 
FOREIGN KEY (player_id) REFERENCES public.profiles(id) ON DELETE SET NULL;

-- raffle_tickets (Future feature, but let's keep schema valid)
ALTER TABLE public.raffle_tickets 
ADD CONSTRAINT raffle_tickets_player_id_fkey 
FOREIGN KEY (player_id) REFERENCES public.profiles(id) ON DELETE SET NULL;

-- 5. RE-CREATE RLS for player_queue
ALTER TABLE public.player_queue ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can update their own queue items" 
ON public.player_queue FOR UPDATE 
USING (auth.uid() = player_id);

CREATE POLICY "Users can cancel their own waiting item" 
ON public.player_queue FOR DELETE 
USING (auth.uid() = player_id AND status = 'waiting');

-- 6. Indexes
CREATE INDEX IF NOT EXISTS idx_profiles_total_wins ON public.profiles(total_wins DESC);

COMMENT ON TABLE public.profiles IS 'Central identity table linked to Auth. Includes stats.';


-- ==========================================
-- SOURCE: 046_smart_promote.sql
-- ==========================================

-- Migration 046: Smart Promote Logic (Fast Lane) - Fixed
-- Modifies promote_next_player to check if selections already exist.

-- Drop first to allow signature changes cleanly
DROP FUNCTION IF EXISTS promote_next_player(integer);

CREATE OR REPLACE FUNCTION promote_next_player(p_screen_number INTEGER)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_next_player RECORD;
  v_next_status TEXT;
BEGIN
  -- 1. Check if screen is free
  IF EXISTS (SELECT 1 FROM public.screen_state WHERE screen_number = p_screen_number AND status != 'idle') THEN
    RETURN FALSE; 
  END IF;

  -- 2. Find oldest waiting player
  SELECT * INTO v_next_player
  FROM public.player_queue
  WHERE screen_number = p_screen_number
    AND status = 'waiting'
  ORDER BY created_at ASC
  LIMIT 1;

  IF v_next_player IS NULL THEN
    RETURN FALSE; 
  END IF;

  -- 3. DETERMINE NEXT STATE (Fast Lane)
  -- If user already selected animals/numbers, we skip 'selecting' and go straight to 'waiting_for_spin'
  IF v_next_player.selected_animals IS NOT NULL AND jsonb_array_length(v_next_player.selected_animals) > 0 THEN
      v_next_status := 'waiting_for_spin';
  ELSE
      -- Legacy flow: user must select on screen (or mobile while on screen)
      v_next_status := 'selecting'; 
  END IF;

  -- 4. Update Queue Status
  UPDATE public.player_queue
  SET status = 'playing' -- They are now the active player
  WHERE id = v_next_player.id;

  -- 5. Update Screen State
  UPDATE public.screen_state
  SET 
    status = v_next_status, -- 'waiting_for_spin' or 'selecting'
    player_id = v_next_player.player_id,
    player_name = v_next_player.player_name, 
    player_emoji = v_next_player.player_emoji
  WHERE screen_number = p_screen_number;

  RETURN TRUE;
END;
$$;


-- ==========================================
-- SOURCE: 047_restore_wheel_selection.sql
-- ==========================================

-- Migration 047: Restore Wheel Selection Logic
-- Adds selected_wheel_id to player_queue and updates promotion logic to sync it to screen_state.

-- 1. Add selected_wheel_id to player_queue if not exists
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'player_queue' AND column_name = 'selected_wheel_id') THEN
        ALTER TABLE public.player_queue
        ADD COLUMN selected_wheel_id UUID REFERENCES public.individual_wheels(id);
    END IF;
END $$;

-- Drop functions first to ensure clean recreation
DROP FUNCTION IF EXISTS promote_next_player(integer);
DROP FUNCTION IF EXISTS force_advance_queue(integer);

-- 2. Update promote_next_player to sync wheel selection
CREATE OR REPLACE FUNCTION promote_next_player(p_screen_number INTEGER)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_next_player RECORD;
  v_next_status TEXT;
  v_default_wheel UUID;
BEGIN
  -- 1. Check if screen is free
  IF EXISTS (SELECT 1 FROM public.screen_state WHERE screen_number = p_screen_number AND status != 'idle') THEN
    RETURN FALSE; 
  END IF;

  -- 2. Find oldest waiting player
  SELECT * INTO v_next_player
  FROM public.player_queue
  WHERE screen_number = p_screen_number
    AND status = 'waiting'
  ORDER BY created_at ASC
  LIMIT 1;

  IF v_next_player IS NULL THEN
    RETURN FALSE; 
  END IF;

  -- 3. DETERMINE NEXT STATE (Fast Lane)
  IF v_next_player.selected_animals IS NOT NULL AND jsonb_array_length(v_next_player.selected_animals) > 0 THEN
      v_next_status := 'waiting_for_spin';
  ELSE
      v_next_status := 'selecting'; 
  END IF;

  -- 4. Update Queue Status
  UPDATE public.player_queue
  SET status = 'playing'
  WHERE id = v_next_player.id;

  -- 5. Update Screen State (INCLUDING WHEEL SELECTION)
  -- If player has specific wheel, use it. Otherwise keep current or default.
  
  UPDATE public.screen_state
  SET 
    status = v_next_status,
    player_id = v_next_player.player_id,
    player_name = v_next_player.player_name, 
    player_emoji = v_next_player.player_emoji,
    current_wheel_id = COALESCE(v_next_player.selected_wheel_id, current_wheel_id)
  WHERE screen_number = p_screen_number;

  RETURN TRUE;
END;
$$;

-- 3. Update force_advance_queue as well (for manual overrides)
CREATE OR REPLACE FUNCTION force_advance_queue(p_screen_number INTEGER)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_next_player RECORD;
BEGIN
    -- 1. Close current active player if any
    UPDATE public.player_queue
    SET status = 'completed'
    WHERE screen_number = p_screen_number 
    AND status IN ('playing', 'selecting');

    -- 2. Reset Screen State
    UPDATE public.screen_state
    SET status = 'idle',
        player_id = NULL,
        player_name = NULL,
        player_emoji = NULL,
        last_spin_result = NULL
    WHERE screen_number = p_screen_number;

    -- 3. Promote Next
    -- We can just call promote_next_player now as it handles the logic
    PERFORM promote_next_player(p_screen_number);
END;
$$;


