  -- 3. DETERMINE NEXT STATE (Fast Lane)
  -- If user already selected animals/numbers, we skip 'selecting' and go straight to 'waiting_for_spin'
  IF v_next_player.selected_animals IS NOT NULL AND jsonb_array_length(v_next_player.selected_animals) > 0 THEN
      v_next_status := 'waiting_for_spin';
  ELSE
      v_next_status := 'selecting'; 
  END IF;

  -- 4. Update Queue Status
  UPDATE public.player_queue
  SET status = 'playing'
  WHERE id = v_next_player.id;

  -- 5. Update Screen State (CRITICAL FIXES HERE)
  UPDATE public.screen_state
  SET 
    status = v_next_status,
    player_id = v_next_player.player_id,
    player_name = v_next_player.player_name, 
    player_emoji = v_next_player.player_emoji,
    -- CRITICAL: Update Wheel ID so screen changes design
    current_wheel_id = v_next_player.selected_wheel_id,
    -- CRITICAL: Update Queue ID so mobile client syncs correctly
    current_queue_id = v_next_player.id,
    updated_at = now()
  WHERE screen_number = p_screen_number;

  RETURN TRUE;
END;
$$;


-- ==========================================
-- SOURCE: 049_fix_double_deduction.sql
-- ==========================================

-- Migration 049: Fix Double Deduction Bug in complete_spin_and_check_package
-- The function was deducting spins twice: once in play_spin and again here.
-- This migration removes the duplicate deduction.

CREATE OR REPLACE FUNCTION complete_spin_and_check_package(
  p_screen_number INTEGER,
  p_result_index INTEGER
) RETURNS JSONB AS $$
DECLARE
  v_current_player RECORD;
  v_package RECORD;
  v_spins_remaining INTEGER;
BEGIN
  -- Obtener jugador actual
  SELECT pq.*, pt.total_spins, pt.spins_consumed
  INTO v_current_player
  FROM player_queue pq
  LEFT JOIN package_tracking pt ON pq.package_tracking_id = pt.id
  WHERE pq.screen_number = p_screen_number 
    AND pq.status = 'playing'
  ORDER BY pq.queue_order ASC
  LIMIT 1;
  
  IF v_current_player IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'message', 'No hay jugador activo'
    );
  END IF;
  
  -- Marcar giro como completado
  UPDATE player_queue 
  SET status = 'completed' 
  WHERE id = v_current_player.id;
  
  -- Actualizar screen_state a showing_result
  UPDATE screen_state
  SET status = 'showing_result',
      last_spin_result = p_result_index,
      updated_at = now()
  WHERE screen_number = p_screen_number;
  
  -- REMOVED: Double deduction bug fix
  -- The spin was already deducted in play_spin RPC
  -- We only need to calculate remaining spins for display
  
  IF v_current_player.package_tracking_id IS NOT NULL THEN
    -- Calcular giros restantes (ya fueron consumidos en play_spin)
    v_spins_remaining := v_current_player.total_spins - v_current_player.spins_consumed;
    
    RETURN jsonb_build_object(
      'success', true,
      'spins_remaining', v_spins_remaining,
      'package_id', v_current_player.package_tracking_id,
      'has_more_spins', v_spins_remaining > 0
    );
  END IF;
  
  -- Sin paquete (pago individual)
  RETURN jsonb_build_object(
    'success', true,
    'spins_remaining', 0,
    'has_more_spins', false
  );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION complete_spin_and_check_package IS 'Marks spin as complete and transitions screen state. Spin deduction happens in play_spin only.';


-- ==========================================
-- SOURCE: 050_server_failsafe.sql
-- ==========================================

-- Migration 050: Server-Side Failsafe for Stuck Spins
-- Automatically completes spins that are stuck for more than 2 minutes

CREATE OR REPLACE FUNCTION auto_complete_stuck_spins()
RETURNS TABLE(fixed_screens INTEGER[], fixed_players INTEGER[]) AS $$
DECLARE
  v_fixed_screens INTEGER[] := ARRAY[]::INTEGER[];
  v_fixed_players INTEGER[] := ARRAY[]::INTEGER[];
  v_screen RECORD;
  v_player RECORD;
BEGIN
  -- 1. Fix screens stuck in 'spinning' or 'showing_result' for > 2 minutes
  FOR v_screen IN 
    SELECT screen_number, status, updated_at
    FROM screen_state
    WHERE status IN ('spinning', 'showing_result')
      AND updated_at < NOW() - INTERVAL '2 minutes'
  LOOP
    -- Force advance to next player
    PERFORM force_advance_queue(v_screen.screen_number);
    
    v_fixed_screens := array_append(v_fixed_screens, v_screen.screen_number);
    
    RAISE NOTICE 'Auto-fixed stuck screen %: was in % for > 2 min', 
      v_screen.screen_number, v_screen.status;
  END LOOP;

  -- 2. Mark players stuck in 'playing' for > 5 minutes as abandoned
  FOR v_player IN
    SELECT id, screen_number, player_name
    FROM player_queue
    WHERE status = 'playing'
      AND created_at < NOW() - INTERVAL '5 minutes'
  LOOP
    UPDATE player_queue
    SET status = 'cancelled'
    WHERE id = v_player.id;
    
    v_fixed_players := array_append(v_fixed_players, v_player.screen_number);
    
    RAISE NOTICE 'Auto-abandoned stuck player % on screen %', 
      v_player.player_name, v_player.screen_number;
  END LOOP;

  RETURN QUERY SELECT v_fixed_screens, v_fixed_players;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION auto_complete_stuck_spins IS 'Failsafe: Auto-completes screens stuck in spinning/showing_result for >2min and marks players stuck in playing for >5min as abandoned';

-- NOTE: This function should be called periodically by:
-- 1. A cron job (pg_cron extension)
-- 2. OR a scheduled Edge Function
-- 3. OR called manually when debugging

-- Example cron setup (requires pg_cron extension):
-- SELECT cron.schedule(
--   'auto-complete-stuck-spins',
--   '*/2 * * * *', -- Every 2 minutes
--   $$SELECT auto_complete_stuck_spins();$$
-- );


-- ==========================================
-- SOURCE: 051_disable_brute_force.sql
-- ==========================================

-- Migration 051: Disable Brute Force Protection
-- Removes rate limiting for testing purposes while maintaining code validation

CREATE OR REPLACE FUNCTION redeem_or_continue_package(
  p_code TEXT,
  p_device_fingerprint TEXT,
  p_screen_number INTEGER,
  p_player_name TEXT,
  p_player_emoji TEXT,
  p_player_id UUID DEFAULT NULL
) RETURNS JSONB AS $$
DECLARE
  v_package RECORD;
  v_next_spin INTEGER;
  v_package_id UUID;
  v_combo RECORD;
BEGIN
  -- ========================================
  -- 🔓 BRUTE FORCE PROTECTION DISABLED
  -- All rate limiting checks removed for testing
  -- ========================================
  
  -- ========================================
  -- 1. PACKAGE LOOKUP & VALIDATION
  -- ========================================
  
  -- Buscar paquete existente en package_tracking
  SELECT * INTO v_package FROM package_tracking WHERE package_code = p_code;
  
  IF v_package IS NULL THEN
    -- Código nuevo - validar con sistema de game_packages
    SELECT * INTO v_combo FROM game_packages 
    WHERE code = p_code 
      AND is_active = true
      AND (is_activated = true OR is_activated IS NULL);
    
    IF v_combo IS NULL THEN
      -- Código inválido - sin rate limiting
      RETURN jsonb_build_object(
        'success', false, 
        'message', 'Código inválido o ya usado'
      );
    END IF;
    
    -- Verificar que tenga jugadas disponibles
    IF v_combo.plays_remaining <= 0 THEN
      RETURN jsonb_build_object(
        'success', false,
        'message', 'Este código ya no tiene giros disponibles'
      );
    END IF;
    
    -- Crear nuevo package_tracking
    INSERT INTO package_tracking (
      package_code,
      total_spins,
      spins_consumed,
      device_fingerprint,
      first_redeemed_at
    ) VALUES (
      p_code,
      v_combo.total_plays,
      0,
      p_device_fingerprint,
      now()
    ) RETURNING id INTO v_package_id;
    
    RETURN jsonb_build_object(
      'success', true,
      'package_id', v_package_id,
      'spin_number', 1,
      'total_spins', v_combo.total_plays,
      'is_new', true
    );
    
  ELSIF v_package.device_fingerprint != p_device_fingerprint THEN
    -- Código ya usado por otro dispositivo
    RETURN jsonb_build_object(
      'success', false, 
      'message', 'Este código ya está siendo usado en otro dispositivo'
    );
    
  ELSIF v_package.spins_consumed >= v_package.total_spins THEN
    -- Sin giros restantes
    RETURN jsonb_build_object(
      'success', false, 
      'message', 'Este código ya no tiene giros disponibles'
    );
    
  ELSE
    -- Continuar con siguiente giro
    v_next_spin := v_package.spins_consumed + 1;
    
    -- Actualizar last_used_at
    UPDATE package_tracking 
    SET last_used_at = now()
    WHERE id = v_package.id;
    
    RETURN jsonb_build_object(
      'success', true, 
      'package_id', v_package.id,
      'spin_number', v_next_spin,
      'total_spins', v_package.total_spins,
      'is_new', false
    );
  END IF;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION redeem_or_continue_package IS 'Redeems a new package or continues an existing one for the same device (BRUTE FORCE PROTECTION DISABLED)';


-- ==========================================
-- SOURCE: 052_add_play_demo_spin.sql
-- ==========================================

-- Migration 052: Add play_demo_spin RPC
-- Enables "Modo Práctica" by allowing free spins that don't affect the queue or packages.

CREATE OR REPLACE FUNCTION play_demo_spin(
  p_screen_number INTEGER
) RETURNS JSONB AS $$
DECLARE
  v_result INTEGER;
  v_wheel_id UUID;
  v_segment_count INTEGER;
  v_rnd_index INTEGER;
BEGIN
  -- 1. Check if screen is IDLE or already in a state that allows demo
  -- (We don't want to overwrite a real player spin)
  IF EXISTS (
    SELECT 1 FROM player_queue 
    WHERE screen_number = p_screen_number 
    AND status IN ('waiting', 'playing', 'ready', 'spinning', 'selecting')
  ) THEN
    RETURN jsonb_build_object('success', false, 'message', 'La pantalla está ocupada');
  END IF;

  -- 2. Determine Result (Logic mirrored from play_spin)
  
  -- A. Detect Active Wheel
  SELECT current_wheel_id INTO v_wheel_id
  FROM screen_state
  WHERE screen_number = p_screen_number;

  -- B. Calculate Result based on Wheel Type
  IF v_wheel_id IS NOT NULL THEN
     -- Custom Wheel: Count segments
     SELECT count(*) INTO v_segment_count
     FROM individual_wheel_segments
     WHERE wheel_id = v_wheel_id;

     IF v_segment_count > 0 THEN
        -- Pick a random segment index (0 to N-1)
        v_rnd_index := floor(random() * v_segment_count)::INTEGER;
        
        -- Get the ACTUAL position ID at that index
        SELECT position INTO v_result
        FROM individual_wheel_segments
        WHERE wheel_id = v_wheel_id
        ORDER BY position ASC
        LIMIT 1 OFFSET v_rnd_index;
     ELSE
        -- Fallback
        v_result := floor(random() * 12) + 1;
     END IF;
  ELSE
     -- Default Mode: Standard 36 Animals
     v_result := floor(random() * 36) + 1;
  END IF;

  -- 3. Update Screen State
  UPDATE screen_state
  SET 
    status = 'spinning',
    is_demo = true,
    player_name = 'Modo Práctica',
    player_emoji = '🎓',
    last_spin_result = v_result,
    updated_at = now()
  WHERE screen_number = p_screen_number;

  -- 4. Return Result
  RETURN jsonb_build_object(
    'success', true,
    'result_index', v_result
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'message', SQLERRM);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION play_demo_spin IS 'Triggers a free demo spin for practice mode without touching the queue.';


-- ==========================================
-- SOURCE: 053_fix_player_queue_constraints.sql
-- ==========================================

-- Migration 053: Fix player_queue status constraints
-- Expands the allowed statuses to include all states used by the system (including failsafes and legacy logic)

BEGIN;

-- 1. Identify and drop the existing check constraint
-- The default name from migration 004 is player_queue_status_check
ALTER TABLE public.player_queue DROP CONSTRAINT IF EXISTS player_queue_status_check;

-- 2. Add the expanded check constraint
-- Added: 'abandoned' (used in failsafe 050), 'spinning', 'showing_result', 'waiting_for_spin' (used in various RPCs/Where clauses)
ALTER TABLE public.player_queue ADD CONSTRAINT player_queue_status_check 
  CHECK (status IN ('waiting', 'selecting', 'ready', 'playing', 'completed', 'cancelled', 'abandoned', 'spinning', 'showing_result', 'waiting_for_spin'));

-- 3. Cleanup: If any rows currently have an invalid status (should not happen if constraint was active, 
-- but good for robustness), we don't need to do anything as we just expanded the list.

COMMIT;

COMMENT ON CONSTRAINT player_queue_status_check ON public.player_queue IS 'Expanded list of allowed player states for system robustness';


-- ==========================================
-- SOURCE: 053_robust_spin_completion.sql
-- ==========================================

-- Migration 053: Robust complete_spin_and_check_package
-- Fixes empty error {} by adding EXCEPTION handling and explicit column selection

CREATE OR REPLACE FUNCTION complete_spin_and_check_package(
  p_screen_number INTEGER,
  p_result_index INTEGER
) RETURNS JSONB AS $$
DECLARE
  v_current_player RECORD;
  v_spins_remaining INTEGER;
BEGIN
  -- 1. Obtener jugador actual (Status = playing)
  -- Usamos columnas explícitas para evitar cualquier ambigüedad de RECORD
  SELECT 
    pq.id, 
    pq.package_tracking_id, 
    pq.selected_animals,
    pt.total_spins, 
    pt.spins_consumed
  INTO v_current_player
  FROM player_queue pq
  LEFT JOIN package_tracking pt ON pq.package_tracking_id = pt.id
  WHERE pq.screen_number = p_screen_number 
    AND pq.status = 'playing'
  ORDER BY pq.queue_order ASC
  LIMIT 1;
  
  -- 2. Validar existencia
  IF v_current_player IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'message', 'No se encontró un jugador activo con estado "playing" en la pantalla ' || p_screen_number::text
    );
  END IF;
  
  -- 3. Marcar giro como completado y GUARDAR EL RESULTADO en el player_queue
  UPDATE player_queue 
  SET status = 'completed',
      spin_result = p_result_index,
      updated_at = now()
  WHERE id = v_current_player.id;
  
  -- 4. Actualizar estado de la pantalla
  UPDATE screen_state
  SET status = 'showing_result',
      last_spin_result = p_result_index,
      updated_at = now()
  WHERE screen_number = p_screen_number;
  
  -- 5. Retornar info de giros restantes (si aplica)
  IF v_current_player.package_tracking_id IS NOT NULL THEN
    -- El giro ya fue descontado en play_spin, aquí solo calculamos para la UI
    v_spins_remaining := v_current_player.total_spins - v_current_player.spins_consumed;
    
    RETURN jsonb_build_object(
      'success', true,
      'spins_remaining', v_spins_remaining,
      'package_id', v_current_player.package_tracking_id,
      'has_more_spins', v_spins_remaining > 0
    );
  END IF;
  
  -- Sin paquete
  RETURN jsonb_build_object(
    'success', true,
    'spins_remaining', 0,
    'has_more_spins', false
  );

EXCEPTION WHEN OTHERS THEN
  -- IMPORTANTE: Capturar el error real para que no regrese un objeto vacío {}
  RETURN jsonb_build_object(
    'success', false,
    'message', SQLERRM,
    'detail', SQLSTATE
  );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


-- ==========================================
-- SOURCE: 054_profiles_self_healing.sql
-- ==========================================

-- Migration 054: Allow self-healing profiles
-- Adds INSERT policy to profiles table so the client can create its own profile if missing

BEGIN;

-- 1. Add INSERT policy (Only for authenticated users creating their OWN profile)
DROP POLICY IF EXISTS "Users can insert their own profile" ON public.profiles;
CREATE POLICY "Users can insert their own profile" 
ON public.profiles FOR INSERT 
WITH CHECK (auth.uid() = id);

-- 2. Ensure Admin Role for the owner
-- We can't do this for every user, but we can make sure the primary admin email is handled correctly in the handle_new_user function if it's called
CREATE OR REPLACE FUNCTION public.handle_new_user() 
RETURNS trigger AS $$
BEGIN
  INSERT INTO public.profiles (id, display_name, email, avatar_url, role)
  VALUES (
    new.id, 
    COALESCE(new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'name', 'Staff'), 
    new.email,
    new.raw_user_meta_data->>'avatar_url',
    CASE 
      WHEN new.email = 'cristianluke@gmail.com' THEN 'admin'
      ELSE 'player' 
    END
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMIT;

COMMENT ON POLICY "Users can insert their own profile" ON public.profiles IS 'Allows the application to self-heal if a profile record is missing for an existing auth user';


-- ==========================================
-- SOURCE: 055_concurrency_and_locks.sql
-- ==========================================

-- Migration 055: Concurrency Control and Expected Queue Verification
-- Enforces row locking (FOR UPDATE) on screen_state during transitions and 
-- updates force_advance_queue to check for expected_queue_id to prevent skipping turns.

-- 1. Drop existing functions to update signatures cleanly
DROP FUNCTION IF EXISTS public.force_advance_queue(INTEGER);
DROP FUNCTION IF EXISTS public.force_advance_queue(INTEGER, UUID);

-- 2. Create updated force_advance_queue with p_expected_queue_id parameter
CREATE OR REPLACE FUNCTION public.force_advance_queue(
  p_screen_number INTEGER,
  p_expected_queue_id UUID DEFAULT NULL
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_active_queue_id UUID;
BEGIN
  -- Bloquear la fila de screen_state para evitar colisiones de concurrencia
  PERFORM 1 
  FROM public.screen_state 
  WHERE screen_number = p_screen_number 
  FOR UPDATE;

  -- Obtener el current_queue_id activo de la pantalla
  SELECT current_queue_id INTO v_active_queue_id
  FROM public.screen_state
  WHERE screen_number = p_screen_number;

  -- Si se espera un ID específico y no coincide, salir inmediatamente (evita carreras críticas)
  IF p_expected_queue_id IS NOT NULL AND (v_active_queue_id IS NULL OR v_active_queue_id != p_expected_queue_id) THEN
    RAISE NOTICE 'Skipping force advance: expected queue ID %, but found %', p_expected_queue_id, v_active_queue_id;
    RETURN;
  END IF;

  -- 1. Cerrar el jugador activo correspondiente si tiene un queue_id válido
  IF v_active_queue_id IS NOT NULL THEN
    UPDATE public.player_queue
    SET status = 'completed'
    WHERE id = v_active_queue_id 
      AND status IN ('playing', 'selecting');
  ELSE
    -- Limpieza de seguridad en caso de registros huérfanos sin queue_id en la pantalla
    UPDATE public.player_queue
    SET status = 'completed'
    WHERE screen_number = p_screen_number 
      AND status IN ('playing', 'selecting');
  END IF;

  -- 2. Reiniciar el estado de la pantalla
  UPDATE public.screen_state
  SET status = 'idle',
      player_id = NULL,
      player_name = NULL,
      player_emoji = NULL,
      last_spin_result = NULL,
      current_queue_id = NULL,
      is_demo = false,
      updated_at = NOW()
  WHERE screen_number = p_screen_number;

  -- 3. Promover al siguiente jugador
  PERFORM public.promote_next_player(p_screen_number);
END;
$$;

COMMENT ON FUNCTION public.force_advance_queue IS 'Advances the screen queue safely, optionally validating the expected active queue ID to prevent concurrent race conditions.';

-- 3. Re-create promote_next_player to include row locking (FOR UPDATE)
CREATE OR REPLACE FUNCTION public.promote_next_player(p_screen_number INTEGER)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_next_player RECORD;
  v_next_status TEXT;
BEGIN
  -- Bloquear fila de la pantalla para evitar dobles asignaciones concurrentes
  PERFORM 1 
  FROM public.screen_state 
  WHERE screen_number = p_screen_number 
  FOR UPDATE;

  -- 1. Check if screen is free
  IF EXISTS (SELECT 1 FROM public.screen_state WHERE screen_number = p_screen_number AND status != 'idle') THEN
    RETURN FALSE; 
  END IF;

  -- 2. Find oldest waiting player
  SELECT * INTO v_next_player
  FROM public.player_queue
  WHERE screen_number = p_screen_number
    AND status = 'waiting'
  ORDER BY created_at ASC
  LIMIT 1;

  IF v_next_player IS NULL THEN
    RETURN FALSE; 
  END IF;

  -- 3. Determine next state (Fast Lane)
  IF v_next_player.selected_animals IS NOT NULL AND jsonb_array_length(v_next_player.selected_animals) > 0 THEN
      v_next_status := 'waiting_for_spin';
  ELSE
      v_next_status := 'selecting'; 
  END IF;

  -- 4. Update Queue Status
  UPDATE public.player_queue
  SET status = 'playing'
  WHERE id = v_next_player.id;

  -- 5. Update Screen State
  UPDATE public.screen_state
  SET 
    status = v_next_status,
    player_id = v_next_player.player_id,
    player_name = v_next_player.player_name, 
    player_emoji = v_next_player.player_emoji,
    current_wheel_id = v_next_player.selected_wheel_id,
    current_queue_id = v_next_player.id,
    updated_at = NOW()
  WHERE screen_number = p_screen_number;

  RETURN TRUE;
END;
$$;


-- ==========================================
-- SOURCE: 056_track_demo_spins.sql
-- ==========================================

-- Migration 056: Track and Limit Demo Spins by Email/Profile
-- Adds demo_spins_used to profiles and updates play_demo_spin to restrict usage.

ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS demo_spins_used INTEGER NOT NULL DEFAULT 0;

-- Drop all existing overloaded versions of play_demo_spin to avoid signature conflicts
DROP FUNCTION IF EXISTS play_demo_spin(integer);
DROP FUNCTION IF EXISTS play_demo_spin(integer, text, text);
DROP FUNCTION IF EXISTS play_demo_spin(integer, text, text, uuid);

CREATE OR REPLACE FUNCTION play_demo_spin(
  p_screen_number INTEGER
) RETURNS JSONB AS $$
DECLARE
  v_result INTEGER;
  v_wheel_id UUID;
  v_segment_count INTEGER;
  v_rnd_index INTEGER;
  v_user_id UUID;
  v_spins_used INTEGER;
BEGIN
  -- 1. Check if user is authenticated
  v_user_id := auth.uid();
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'message', 'Debes iniciar sesión para usar el modo de práctica.');
  END IF;

  -- 2. Check if screen is IDLE and queue is empty
  -- (We don't want to overwrite a real player spin)
  IF EXISTS (
    SELECT 1 FROM player_queue 
    WHERE screen_number = p_screen_number 
    AND status IN ('waiting', 'playing', 'ready', 'spinning', 'selecting')
  ) OR EXISTS (
    SELECT 1 FROM screen_state
    WHERE screen_number = p_screen_number
    AND status != 'idle'
  ) THEN
    RETURN jsonb_build_object('success', false, 'message', 'La pantalla está ocupada');
  END IF;

  -- 3. Check demo spin limits from user profile
  SELECT COALESCE(demo_spins_used, 0) INTO v_spins_used
  FROM public.profiles
  WHERE id = v_user_id;

  IF v_spins_used IS NULL THEN
    v_spins_used := 0;
  END IF;

  IF v_spins_used >= 2 THEN
    RETURN jsonb_build_object('success', false, 'message', 'Has agotado tus giros de práctica gratuitos (máximo 2)');
  END IF;

  -- 4. Determine Result (Logic mirrored from play_spin)
  
  -- A. Detect Active Wheel
  SELECT current_wheel_id INTO v_wheel_id
  FROM screen_state
  WHERE screen_number = p_screen_number;

  -- B. Calculate Result based on Wheel Type
  IF v_wheel_id IS NOT NULL THEN
     -- Custom Wheel: Count segments
     SELECT count(*) INTO v_segment_count
     FROM individual_wheel_segments
     WHERE wheel_id = v_wheel_id;

     IF v_segment_count > 0 THEN
        -- Pick a random segment index (0 to N-1)
        v_rnd_index := floor(random() * v_segment_count)::INTEGER;
        
        -- Get the ACTUAL position ID at that index
        SELECT position INTO v_result
        FROM individual_wheel_segments
        WHERE wheel_id = v_wheel_id
        ORDER BY position ASC
        LIMIT 1 OFFSET v_rnd_index;
     ELSE
        -- Fallback
        v_result := floor(random() * 12) + 1;
     END IF;
  ELSE
     -- Default Mode: Standard 36 Animals
     v_result := floor(random() * 36) + 1;
  END IF;

  -- 5. Increment user's demo spin count
  IF EXISTS (SELECT 1 FROM public.profiles WHERE id = v_user_id) THEN
    UPDATE public.profiles
    SET demo_spins_used = v_spins_used + 1,
        updated_at = now()
    WHERE id = v_user_id;
  ELSE
    INSERT INTO public.profiles (id, display_name, email, demo_spins_used)
    VALUES (
      v_user_id,
      COALESCE(auth.jwt() ->> 'name', 'Jugador'),
      COALESCE(auth.jwt() ->> 'email', 'unknown@ejemplo.com'),
      1
    );
  END IF;

  -- 6. Update Screen State
  UPDATE screen_state
  SET 
    status = 'spinning',
    is_demo = true,
    player_name = 'Modo Práctica',
    player_emoji = '🎓',
    last_spin_result = v_result,
    updated_at = now()
  WHERE screen_number = p_screen_number;

  -- 7. Return Result
  RETURN jsonb_build_object(
    'success', true,
    'result_index', v_result
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'message', SQLERRM);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

COMMENT ON FUNCTION play_demo_spin IS 'Triggers a free demo spin for practice mode for authenticated users, checking limits and screen availability.';


